INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (496, '健康', 1, 1, 'health', 'jiankang');
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (497, '医疗', 1, 1, 'medical', 'yiliao');
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (498, '医院', 1, 1, 'hospital', 'yiyuan');
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (499, '医生', 1, 1, 'doctor', 'yisheng');
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (500, '护士', 1, 1, 'nurse', 'hushi');
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (501, '《关雎》\n关关雎鸠，在河之洲。\n窈窕淑女，君子好逑。\n参差荇菜，左右流之。\n窈窕淑女，寤寐求之。\n求之不得，寤寐思服。\n悠哉悠哉，辗转反侧。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (502, '《蒹葭》\n蒹葭苍苍，白露为霜。\n所谓伊人，在水一方。\n溯洄从之，道阻且长。\n溯游从之，宛在水中央。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (503, '《采薇》（节选）\n昔我往矣，杨柳依依。\n今我来思，雨雪霏霏。\n行道迟迟，载渴载饥。\n我心伤悲，莫知我哀！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (504, '《离骚》（节选）\n路漫漫其修远兮，吾将上下而求索。\n饮余马于咸池兮，总余辔乎扶桑。\n折若木以拂日兮，聊逍遥以相羊。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (505, '《大风歌》\n大风起兮云飞扬，\n威加海内兮归故乡，\n安得猛士兮守四方！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (506, '《长歌行》\n青青园中葵，朝露待日晞。\n阳春布德泽，万物生光辉。\n常恐秋节至，焜黄华叶衰。\n百川东到海，何时复西归？\n少壮不努力，老大徒伤悲。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (507, '《短歌行》（节选）\n对酒当歌，人生几何！\n譬如朝露，去日苦多。\n慨当以慷，忧思难忘。\n何以解忧？唯有杜康。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (508, '《龟虽寿》\n神龟虽寿，犹有竟时。\n腾蛇乘雾，终为土灰。\n老骥伏枥，志在千里。\n烈士暮年，壮心不已。\n盈缩之期，不但在天；\n养怡之福，可得永年。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (509, '《饮酒·其五》\n结庐在人境，而无车马喧。\n问君何能尔？心远地自偏。\n采菊东篱下，悠然见南山。\n山气日夕佳，飞鸟相与还。\n此中有真意，欲辨已忘言。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (510, '《杂诗》\n人生无根蒂，飘如陌上尘。\n分散逐风转，此已非常身。\n落地为兄弟，何必骨肉亲！\n得欢当作乐，斗酒聚比邻。\n盛年不重来，一日难再晨。\n及时当勉励，岁月不待人。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (511, '《登池上楼》\n潜虬媚幽姿，飞鸿响远音。\n薄霄愧云浮，栖川怍渊沉。\n进德智所拙，退耕力不任。\n徇禄反穷海，卧疴对空林。\n衾枕昧节候，褰开暂窥临。\n倾耳聆波澜，举目眺岖嵚。\n初景革绪风，新阳改故阴。\n池塘生春草，园柳变鸣禽。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (512, '《晚登三山还望京邑》\n灞涘望长安，河阳视京县。\n白日丽飞甍，参差皆可见。\n余霞散成绮，澄江静如练。\n喧鸟覆春洲，杂英满芳甸。\n去矣方滞淫，怀哉罢欢宴。\n佳期怅何许，泪下如流霰。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (513, '《入若耶溪》\n艅艎何泛泛，空水共悠悠。\n阴霞生远岫，阳景逐回流。\n蝉噪林逾静，鸟鸣山更幽。\n此地动归念，长年悲倦游。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (514, '《赠范晔》\n折花逢驿使，寄与陇头人。\n江南无所有，聊赠一枝春。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (515, '《野望》\n东皋薄暮望，徙倚欲何依。\n树树皆秋色，山山唯落晖。\n牧人驱犊返，猎马带禽归。\n相顾无相识，长歌怀采薇。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (516, '《送杜少府之任蜀州》\n城阙辅三秦，风烟望五津。\n与君离别意，同是宦游人。\n海内存知己，天涯若比邻。\n无为在歧路，儿女共沾巾。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (517, '《滕王阁诗》\n滕王高阁临江渚，佩玉鸣鸾罢歌舞。\n画栋朝飞南浦云，珠帘暮卷西山雨。\n闲云潭影日悠悠，物换星移几度秋。\n阁中帝子今何在？槛外长江空自流。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (518, '《登幽州台歌》\n前不见古人，后不见来者。\n念天地之悠悠，独怆然而涕下。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (519, '《春江花月夜》（节选）\n春江潮水连海平，海上明月共潮生。\n滟滟随波千万里，何处春江无月明！\n江流宛转绕芳甸，月照花林皆似霰。\n空里流霜不觉飞，汀上白沙看不见。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (520, '《望月怀远》\n海上生明月，天涯共此时。\n情人怨遥夜，竟夕起相思。\n灭烛怜光满，披衣觉露滋。\n不堪盈手赠，还寝梦佳期。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (521, '《凉州词》\n黄河远上白云间，一片孤城万仞山。\n羌笛何须怨杨柳，春风不度玉门关。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (522, '《登鹳雀楼》\n白日依山尽，黄河入海流。\n欲穷千里目，更上一层楼。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (523, '《春晓》\n春眠不觉晓，处处闻啼鸟。\n夜来风雨声，花落知多少。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (524, '《凉州词》\n葡萄美酒夜光杯，欲饮琵琶马上催。\n醉卧沙场君莫笑，古来征战几人回？', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (525, '《出塞》\n秦时明月汉时关，万里长征人未还。\n但使龙城飞将在，不教胡马度阴山。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (526, '《从军行》\n青海长云暗雪山，孤城遥望玉门关。\n黄沙百战穿金甲，不破楼兰终不还。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (527, '《芙蓉楼送辛渐》\n寒雨连江夜入吴，平明送客楚山孤。\n洛阳亲友如相问，一片冰心在玉壶。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (528, '《山居秋暝》\n空山新雨后，天气晚来秋。\n明月松间照，清泉石上流。\n竹喧归浣女，莲动下渔舟。\n随意春芳歇，王孙自可留。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (529, '《使至塞上》\n单车欲问边，属国过居延。\n征蓬出汉塞，归雁入胡天。\n大漠孤烟直，长河落日圆。\n萧关逢候骑，都护在燕然。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (530, '《送元二使安西》\n渭城朝雨浥轻尘，客舍青青柳色新。\n劝君更尽一杯酒，西出阳关无故人。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (531, '《九月九日忆山东兄弟》\n独在异乡为异客，每逢佳节倍思亲。\n遥知兄弟登高处，遍插茱萸少一人。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (532, '《相思》\n红豆生南国，春来发几枝。\n愿君多采撷，此物最相思。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (533, '《杂诗》\n君自故乡来，应知故乡事。\n来日绮窗前，寒梅著花未？', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (534, '《静夜思》\n床前明月光，疑是地上霜。\n举头望明月，低头思故乡。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (535, '《望庐山瀑布》\n日照香炉生紫烟，遥看瀑布挂前川。\n飞流直下三千尺，疑是银河落九天。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (536, '《早发白帝城》\n朝辞白帝彩云间，千里江陵一日还。\n两岸猿声啼不住，轻舟已过万重山。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (537, '《宣州谢朓楼饯别校书叔云》\n弃我去者，昨日之日不可留；\n乱我心者，今日之日多烦忧。\n长风万里送秋雁，对此可以酣高楼。\n蓬莱文章建安骨，中间小谢又清发。\n俱怀逸兴壮思飞，欲上青天览明月。\n抽刀断水水更流，举杯消愁愁更愁。\n人生在世不称意，明朝散发弄扁舟。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (538, '《将进酒》（节选）\n君不见黄河之水天上来，奔流到海不复回。\n君不见高堂明镜悲白发，朝如青丝暮成雪。\n人生得意须尽欢，莫使金樽空对月。\n天生我材必有用，千金散尽还复来。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (539, '《行路难》\n金樽清酒斗十千，玉盘珍羞直万钱。\n停杯投箸不能食，拔剑四顾心茫然。\n欲渡黄河冰塞川，将登太行雪满山。\n闲来垂钓碧溪上，忽复乘舟梦日边。\n行路难！行路难！多歧路，今安在？\n长风破浪会有时，直挂云帆济沧海。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (540, '《梦游天姥吟留别》（节选）\n安能摧眉折腰事权贵，使我不得开心颜！\n世间行乐亦如此，古来万事东流水。\n别君去兮何时还？且放白鹿青崖间，须行即骑访名山。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (541, '《望岳》\n岱宗夫如何？齐鲁青未了。\n造化钟神秀，阴阳割昏晓。\n荡胸生曾云，决眦入归鸟。\n会当凌绝顶，一览众山小。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (542, '《春望》\n国破山河在，城春草木深。\n感时花溅泪，恨别鸟惊心。\n烽火连三月，家书抵万金。\n白头搔更短，浑欲不胜簪。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (543, '《春夜喜雨》\n好雨知时节，当春乃发生。\n随风潜入夜，润物细无声。\n野径云俱黑，江船火独明。\n晓看红湿处，花重锦官城。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (544, '《旅夜书怀》\n细草微风岸，危樯独夜舟。\n星垂平野阔，月涌大江流。\n名岂文章著，官应老病休。\n飘飘何所似，天地一沙鸥。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (545, '《登高》\n风急天高猿啸哀，渚清沙白鸟飞回。\n无边落木萧萧下，不尽长江滚滚来。\n万里悲秋常作客，百年多病独登台。\n艰难苦恨繁霜鬓，潦倒新停浊酒杯。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (546, '《绝句》\n两个黄鹂鸣翠柳，一行白鹭上青天。\n窗含西岭千秋雪，门泊东吴万里船。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (547, '《白雪歌送武判官归京》（节选）\n北风卷地白草折，胡天八月即飞雪。\n忽如一夜春风来，千树万树梨花开。\n散入珠帘湿罗幕，狐裘不暖锦衾薄。\n将军角弓不得控，都护铁衣冷难着。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (548, '《逢入京使》\n故园东望路漫漫，双袖龙钟泪不干。\n马上相逢无纸笔，凭君传语报平安。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (549, '《游子吟》\n慈母手中线，游子身上衣。\n临行密密缝，意恐迟迟归。\n谁言寸草心，报得三春晖。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (550, '《早春呈水部张十八员外》\n天街小雨润如酥，草色遥看近却无。\n最是一年春好处，绝胜烟柳满皇都。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (551, '《酬乐天扬州初逢席上见赠》\n巴山楚水凄凉地，二十三年弃置身。\n怀旧空吟闻笛赋，到乡翻似烂柯人。\n沉舟侧畔千帆过，病树前头万木春。\n今日听君歌一曲，暂凭杯酒长精神。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (552, '《乌衣巷》\n朱雀桥边野草花，乌衣巷口夕阳斜。\n旧时王谢堂前燕，飞入寻常百姓家。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (553, '《赋得古原草送别》\n离离原上草，一岁一枯荣。\n野火烧不尽，春风吹又生。\n远芳侵古道，晴翠接荒城。\n又送王孙去，萋萋满别情。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (554, '《钱塘湖春行》\n孤山寺北贾亭西，水面初平云脚低。\n几处早莺争暖树，谁家新燕啄春泥。\n乱花渐欲迷人眼，浅草才能没马蹄。\n最爱湖东行不足，绿杨阴里白沙堤。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (555, '《暮江吟》\n一道残阳铺水中，半江瑟瑟半江红。\n可怜九月初三夜，露似真珠月似弓。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (556, '《忆江南》\n江南好，风景旧曾谙。\n日出江花红胜火，春来江水绿如蓝。\n能不忆江南？', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (557, '《悯农》\n锄禾日当午，汗滴禾下土。\n谁知盘中餐，粒粒皆辛苦。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (558, '《江雪》\n千山鸟飞绝，万径人踪灭。\n孤舟蓑笠翁，独钓寒江雪。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (559, '《寻隐者不遇》\n松下问童子，言师采药去。\n只在此山中，云深不知处。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (560, '《枫桥夜泊》\n月落乌啼霜满天，江枫渔火对愁眠。\n姑苏城外寒山寺，夜半钟声到客船。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (561, '《渔歌子》\n西塞山前白鹭飞，桃花流水鳜鱼肥。\n青箬笠，绿蓑衣，斜风细雨不须归。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (562, '《滁州西涧》\n独怜幽草涧边生，上有黄鹂深树鸣。\n春潮带雨晚来急，野渡无人舟自横。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (563, '《塞下曲》\n月黑雁飞高，单于夜遁逃。\n欲将轻骑逐，大雪满弓刀。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (564, '《游山西村》\n莫笑农家腊酒浑，丰年留客足鸡豚。\n山重水复疑无路，柳暗花明又一村。\n箫鼓追随春社近，衣冠简朴古风存。\n从今若许闲乘月，拄杖无时夜叩门。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (565, '《示儿》\n死去元知万事空，但悲不见九州同。\n王师北定中原日，家祭无忘告乃翁。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (566, '《秋夜将晓出篱门迎凉有感》\n三万里河东入海，五千仞岳上摩天。\n遗民泪尽胡尘里，南望王师又一年。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (567, '《十一月四日风雨大作》\n僵卧孤村不自哀，尚思为国戍轮台。\n夜阑卧听风吹雨，铁马冰河入梦来。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (568, '《卜算子·咏梅》\n驿外断桥边，寂寞开无主。\n已是黄昏独自愁，更著风和雨。\n无意苦争春，一任群芳妒。\n零落成泥碾作尘，只有香如故。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (569, '《冬夜读书示子聿》\n古人学问无遗力，少壮工夫老始成。\n纸上得来终觉浅，绝知此事要躬行。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (570, '《小池》\n泉眼无声惜细流，树阴照水爱晴柔。\n小荷才露尖尖角，早有蜻蜓立上头。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (571, '《晓出净慈寺送林子方》\n毕竟西湖六月中，风光不与四时同。\n接天莲叶无穷碧，映日荷花别样红。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (572, '《春日》\n胜日寻芳泗水滨，无边光景一时新。\n等闲识得东风面，万紫千红总是春。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (573, '《观书有感》\n半亩方塘一鉴开，天光云影共徘徊。\n问渠那得清如许？为有源头活水来。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (574, '《题临安邸》\n山外青山楼外楼，西湖歌舞几时休？\n暖风熏得游人醉，直把杭州作汴州。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (575, '《游园不值》\n应怜屐齿印苍苔，小扣柴扉久不开。\n春色满园关不住，一枝红杏出墙来。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (576, '《乡村四月》\n绿遍山原白满川，子规声里雨如烟。\n乡村四月闲人少，才了蚕桑又插田。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (577, '《墨梅》\n我家洗砚池头树，朵朵花开淡墨痕。\n不要人夸好颜色，只留清气满乾坤。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (578, '《石灰吟》\n千锤万凿出深山，烈火焚烧若等闲。\n粉骨碎身全不怕，要留清白在人间。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (579, '《竹石》\n咬定青山不放松，立根原在破岩中。\n千磨万击还坚劲，任尔东西南北风。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (580, '《己亥杂诗》\n九州生气恃风雷，万马齐喑究可哀。\n我劝天公重抖擞，不拘一格降人才。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (581, '《村居》\n草长莺飞二月天，拂堤杨柳醉春烟。\n儿童散学归来早，忙趁东风放纸鸢。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (582, '《所见》\n牧童骑黄牛，歌声振林樾。\n意欲捕鸣蝉，忽然闭口立。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (583, '《长相思》\n山一程，水一程，身向榆关那畔行，夜深千帐灯。\n风一更，雪一更，聒碎乡心梦不成，故园无此声。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (584, '《浣溪沙》\n谁念西风独自凉？萧萧黄叶闭疏窗。沉思往事立残阳。\n被酒莫惊春睡重，赌书消得泼茶香。当时只道是寻常。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (585, '《木兰花令·拟古决绝词》\n人生若只如初见，何事秋风悲画扇。\n等闲变却故人心，却道故人心易变。\n骊山语罢清宵半，泪雨霖铃终不怨。\n何如薄幸锦衣郎，比翼连枝当日愿。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (586, '《蝶恋花》\n辛苦最怜天上月，一昔如环，昔昔都成玦。\n若似月轮终皎洁，不辞冰雪为卿热。\n无那尘缘容易绝，燕子依然，软踏帘钩说。\n唱罢秋坟愁未歇，春丛认取双栖蝶。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (587, '《采桑子》\n谁翻乐府凄凉曲？风也萧萧，雨也萧萧，瘦尽灯花又一宵。\n不知何事萦怀抱，醒也无聊，醉也无聊，梦也何曾到谢桥。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (588, '《画堂春》\n一生一代一双人，争教两处销魂。\n相思相望不相亲，天为谁春？\n浆向蓝桥易乞，药成碧海难奔。\n若容相访饮牛津，相对忘贫。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (589, '《虞美人》\n银床淅沥青梧老，屧粉秋蛩扫。\n采香行处蹙连钱，拾得翠翘何恨不能言。\n回廊一寸相思地，落月成孤倚。\n背灯和月就花阴，已是十年踪迹十年心。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (590, '《南乡子》\n泪咽却无声，只向从前悔薄情。\n凭仗丹青重省识，盈盈，一片伤心画不成。\n别语忒分明，午夜鹣鹣梦早醒。\n卿自早醒侬自梦，更更，泣尽风檐夜雨铃。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (591, '《金缕曲》\n德也狂生耳！\n偶然间、淄尘京国，乌衣门第。\n有酒惟浇赵州土，谁会成生此意？\n不信道、遂成知己。\n青眼高歌俱未老，向尊前、拭尽英雄泪。\n君不见，月如水。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (592, '《水调歌头》\n明月几时有？把酒问青天。\n不知天上宫阙，今夕是何年。\n我欲乘风归去，又恐琼楼玉宇，高处不胜寒。\n起舞弄清影，何似在人间。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (593, '《念奴娇·赤壁怀古》\n大江东去，浪淘尽，千古风流人物。\n故垒西边，人道是，三国周郎赤壁。\n乱石穿空，惊涛拍岸，卷起千堆雪。\n江山如画，一时多少豪杰。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (594, '《江城子·乙卯正月二十日夜记梦》\n十年生死两茫茫，不思量，自难忘。\n千里孤坟，无处话凄凉。\n纵使相逢应不识，尘满面，鬓如霜。\n夜来幽梦忽还乡，小轩窗，正梳妆。\n相顾无言，惟有泪千行。\n料得年年肠断处，明月夜，短松冈。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (595, '《定风波》\n莫听穿林打叶声，何妨吟啸且徐行。\n竹杖芒鞋轻胜马，谁怕？一蓑烟雨任平生。\n料峭春风吹酒醒，微冷，山头斜照却相迎。\n回首向来萧瑟处，归去，也无风雨也无晴。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (596, '《蝶恋花·春景》\n花褪残红青杏小。燕子飞时，绿水人家绕。\n枝上柳绵吹又少，天涯何处无芳草！\n墙里秋千墙外道。墙外行人，墙里佳人笑。\n笑渐不闻声渐悄，多情却被无情恼。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (597, '《临江仙》\n夜饮东坡醒复醉，归来仿佛三更。\n家童鼻息已雷鸣。敲门都不应，倚杖听江声。\n长恨此身非我有，何时忘却营营？\n夜阑风静縠纹平。小舟从此逝，江海寄余生。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (598, '《鹊桥仙》\n纤云弄巧，飞星传恨，银汉迢迢暗度。\n金风玉露一相逢，便胜却人间无数。\n柔情似水，佳期如梦，忍顾鹊桥归路。\n两情若是久长时，又岂在朝朝暮暮。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (599, '《青玉案·元夕》\n东风夜放花千树，更吹落、星如雨。\n宝马雕车香满路。\n凤箫声动，玉壶光转，一夜鱼龙舞。\n蛾儿雪柳黄金缕，笑语盈盈暗香去。\n众里寻他千百度，蓦然回首，那人却在，灯火阑珊处。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (600, '《破阵子·为陈同甫赋壮词以寄之》\n醉里挑灯看剑，梦回吹角连营。\n八百里分麾下炙，五十弦翻塞外声。沙场秋点兵。\n马作的卢飞快，弓如霹雳弦惊。\n了却君王天下事，赢得生前身后名。可怜白发生！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (601, '《永遇乐·京口北固亭怀古》\n千古江山，英雄无觅，孙仲谋处。\n舞榭歌台，风流总被，雨打风吹去。\n斜阳草树，寻常巷陌，人道寄奴曾住。\n想当年，金戈铁马，气吞万里如虎。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (602, '《菩萨蛮·书江西造口壁》\n郁孤台下清江水，中间多少行人泪。\n西北望长安，可怜无数山。\n青山遮不住，毕竟东流去。\n江晚正愁余，山深闻鹧鸪。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (603, '《鹧鸪天》\n壮岁旌旗拥万夫，锦襜突骑渡江初。\n燕兵夜娖银胡觮，汉箭朝飞金仆姑。\n追往事，叹今吾，春风不染白髭须。\n却将万字平戎策，换得东家种树书。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (604, '《西江月·夜行黄沙道中》\n明月别枝惊鹊，清风半夜鸣蝉。\n稻花香里说丰年，听取蛙声一片。\n七八个星天外，两三点雨山前。\n旧时茅店社林边，路转溪桥忽见。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (605, '《清平乐·村居》\n茅檐低小，溪上青青草。\n醉里吴音相媚好，白发谁家翁媪？\n大儿锄豆溪东，中儿正织鸡笼。\n最喜小儿亡赖，溪头卧剥莲蓬。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (606, '《丑奴儿·书博山道中壁》\n少年不识愁滋味，爱上层楼。爱上层楼，为赋新词强说愁。\n而今识尽愁滋味，欲说还休。欲说还休，却道天凉好个秋。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (607, '《南乡子·登京口北固亭有怀》\n何处望神州？满眼风光北固楼。\n千古兴亡多少事？悠悠。不尽长江滚滚流。\n年少万兜鍪，坐断东南战未休。\n天下英雄谁敌手？曹刘。生子当如孙仲谋。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (608, '《摸鱼儿》\n更能消、几番风雨，匆匆春又归去。\n惜春长怕花开早，何况落红无数。\n春且住，见说道、天涯芳草无归路。\n怨春不语。算只有殷勤，画檐蛛网，尽日惹飞絮。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (609, '《扬州慢》\n淮左名都，竹西佳处，解鞍少驻初程。\n过春风十里，尽荠麦青青。\n自胡马窥江去后，废池乔木，犹厌言兵。\n渐黄昏，清角吹寒，都在空城。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (610, '《暗香》\n旧时月色，算几番照我，梅边吹笛？\n唤起玉人，不管清寒与攀摘。\n何逊而今渐老，都忘却、春风词笔。\n但怪得、竹外疏花，香冷入瑶席。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (611, '《疏影》\n苔枝缀玉，有翠禽小小，枝上同宿。\n客里相逢，篱角黄昏，无言自倚修竹。\n昭君不惯胡沙远，但暗忆、江南江北。\n想佩环、月夜归来，化作此花幽独。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (612, '《一剪梅》\n红藕香残玉簟秋。轻解罗裳，独上兰舟。\n云中谁寄锦书来？雁字回时，月满西楼。\n花自飘零水自流。一种相思，两处闲愁。\n此情无计可消除，才下眉头，却上心头。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (613, '《醉花阴》\n薄雾浓云愁永昼，瑞脑消金兽。\n佳节又重阳，玉枕纱厨，半夜凉初透。\n东篱把酒黄昏后，有暗香盈袖。\n莫道不消魂，帘卷西风，人比黄花瘦。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (614, '《声声慢》\n寻寻觅觅，冷冷清清，凄凄惨惨戚戚。\n乍暖还寒时候，最难将息。\n三杯两盏淡酒，怎敌他、晚来风急？\n雁过也，正伤心，却是旧时相识。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (615, '《武陵春》\n风住尘香花已尽，日晚倦梳头。\n物是人非事事休，欲语泪先流。\n闻说双溪春尚好，也拟泛轻舟。\n只恐双溪舴艋舟，载不动许多愁。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (616, '《如梦令》\n常记溪亭日暮，沉醉不知归路。\n兴尽晚回舟，误入藕花深处。\n争渡，争渡，惊起一滩鸥鹭。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (617, '《点绛唇》\n蹴罢秋千，起来慵整纤纤手。\n露浓花瘦，薄汗轻衣透。\n见客入来，袜刬金钗溜。\n和羞走，倚门回首，却把青梅嗅。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (618, '《渔家傲》\n天接云涛连晓雾，星河欲转千帆舞。\n仿佛梦魂归帝所。闻天语，殷勤问我归何处。\n我报路长嗟日暮，学诗谩有惊人句。\n九万里风鹏正举。风休住，蓬舟吹取三山去！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (619, '《蝶恋花》\n泪湿罗衣脂粉满，四叠阳关，唱到千千遍。\n人道山长山又断，萧萧微雨闻孤馆。\n惜别伤离方寸乱，忘了临行，酒盏深和浅。\n好把音书凭过雁，东莱不似蓬莱远。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (620, '《鹧鸪天》\n暗淡轻黄体性柔，情疏迹远只香留。\n何须浅碧深红色，自是花中第一流。\n梅定妒，菊应羞，画阑开处冠中秋。\n骚人可煞无情思，何事当年不见收。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (621, '《永遇乐》\n落日熔金，暮云合璧，人在何处？\n染柳烟浓，吹梅笛怨，春意知几许？\n元宵佳节，融和天气，次第岂无风雨？\n来相召、香车宝马，谢他酒朋诗侣。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (622, '《凤凰台上忆吹箫》\n香冷金猊，被翻红浪，起来慵自梳头。\n任宝奁尘满，日上帘钩。\n生怕离怀别苦，多少事、欲说还休。\n新来瘦，非干病酒，不是悲秋。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (623, '《念奴娇·过洞庭》\n洞庭青草，近中秋、更无一点风色。\n玉鉴琼田三万顷，着我扁舟一叶。\n素月分辉，明河共影，表里俱澄澈。\n悠然心会，妙处难与君说。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (624, '《六州歌头》\n长淮望断，关塞莽然平。\n征尘暗，霜风劲，悄边声。黯销凝。\n追想当年事，殆天数，非人力；\n洙泗上，弦歌地，亦膻腥。\n隔水毡乡，落日牛羊下，区脱纵横。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (625, '《贺新郎·送胡邦衡待制赴新州》\n梦绕神州路。\n怅秋风、连营画角，故宫离黍。\n底事昆仑倾砥柱，九地黄流乱注？\n聚万落千村狐兔。\n天意从来高难问，况人情老易悲难诉！\n更南浦，送君去。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (626, '《钗头凤》\n红酥手，黄縢酒，满城春色宫墙柳。\n东风恶，欢情薄。\n一怀愁绪，几年离索。错、错、错。\n春如旧，人空瘦，泪痕红浥鲛绡透。\n桃花落，闲池阁。\n山盟虽在，锦书难托。莫、莫、莫！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (627, '《诉衷情》\n当年万里觅封侯，匹马戍梁州。\n关河梦断何处？尘暗旧貂裘。\n胡未灭，鬓先秋，泪空流。\n此生谁料，心在天山，身老沧洲。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (628, '《卜算子·咏梅》\n驿外断桥边，寂寞开无主。\n已是黄昏独自愁，更著风和雨。\n无意苦争春，一任群芳妒。\n零落成泥碾作尘，只有香如故。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (629, '《夜游宫》\n雪晓清笳乱起，梦游处、不知何地。\n铁骑无声望似水。\n想关河，雁门西，青海际。\n睡觉寒灯里，漏声断、月斜窗纸。\n自许封侯在万里。\n有谁知，鬓虽残，心未死！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (630, '《鹊桥仙》\n一竿风月，一蓑烟雨，家在钓台西住。\n卖鱼生怕近城门，况肯到红尘深处？\n潮生理棹，潮平系缆，潮落浩歌归去。\n时人错把比严光，我自是无名渔父。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (631, '《谢池春》\n壮岁从戎，曾是气吞残虏。\n阵云高、狼烟夜举。\n朱颜青鬓，拥雕戈西戍。\n笑儒冠、自来多误。\n功名梦断，却泛扁舟吴楚。\n漫悲歌、伤怀吊古。\n烟波无际，望秦关何处？\n叹流年、又成虚度。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (632, '《汉宫春·立春日》\n春已归来，看美人头上，袅袅春幡。\n无端风雨，未肯收尽余寒。\n年时燕子，料今宵、梦到西园。\n浑未办、黄柑荐酒，更传青韭堆盘？', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (633, '《水龙吟·登建康赏心亭》\n楚天千里清秋，水随天去秋无际。\n遥岑远目，献愁供恨，玉簪螺髻。\n落日楼头，断鸿声里，江南游子。\n把吴钩看了，栏杆拍遍，无人会，登临意。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (634, '《摸鱼儿·更能消几番风雨》\n更能消、几番风雨，匆匆春又归去。\n惜春长怕花开早，何况落红无数。\n春且住，见说道、天涯芳草无归路。\n怨春不语。算只有殷勤，画檐蛛网，尽日惹飞絮。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (635, '《永遇乐·京口北固亭怀古》\n千古江山，英雄无觅，孙仲谋处。\n舞榭歌台，风流总被，雨打风吹去。\n斜阳草树，寻常巷陌，人道寄奴曾住。\n想当年，金戈铁马，气吞万里如虎。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (636, '《菩萨蛮·书江西造口壁》\n郁孤台下清江水，中间多少行人泪。\n西北望长安，可怜无数山。\n青山遮不住，毕竟东流去。\n江晚正愁余，山深闻鹧鸪。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (637, '《青玉案·元夕》\n东风夜放花千树，更吹落、星如雨。\n宝马雕车香满路。\n凤箫声动，玉壶光转，一夜鱼龙舞。\n蛾儿雪柳黄金缕，笑语盈盈暗香去。\n众里寻他千百度，蓦然回首，那人却在，灯火阑珊处。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (638, '《破阵子·为陈同甫赋壮词以寄之》\n醉里挑灯看剑，梦回吹角连营。\n八百里分麾下炙，五十弦翻塞外声。沙场秋点兵。\n马作的卢飞快，弓如霹雳弦惊。\n了却君王天下事，赢得生前身后名。可怜白发生！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (639, '《鹧鸪天·送人》\n唱彻《阳关》泪未干，功名馀事且加餐。\n浮天水送无穷树，带雨云埋一半山。\n今古恨，几千般，只应离合是悲欢？\n江头未是风波恶，别有人间行路难！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (640, '《西江月·遣兴》\n醉里且贪欢笑，要愁那得工夫。\n近来始觉古人书，信著全无是处。\n昨夜松边醉倒，问松我醉何如。\n只疑松动要来扶，以手推松曰去。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (641, '《丑奴儿·书博山道中壁》\n少年不识愁滋味，爱上层楼。爱上层楼，为赋新词强说愁。\n而今识尽愁滋味，欲说还休。欲说还休，却道天凉好个秋。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (642, '《清平乐·村居》\n茅檐低小，溪上青青草。\n醉里吴音相媚好，白发谁家翁媪？\n大儿锄豆溪东，中儿正织鸡笼。\n最喜小儿亡赖，溪头卧剥莲蓬。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (643, '《南乡子·登京口北固亭有怀》\n何处望神州？满眼风光北固楼。\n千古兴亡多少事？悠悠。不尽长江滚滚流。\n年少万兜鍪，坐断东南战未休。\n天下英雄谁敌手？曹刘。生子当如孙仲谋。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (644, '《水调歌头·盟鸥》\n带湖吾甚爱，千丈翠奁开。\n先生杖屦无事，一日走千回。\n凡我同盟鸥鹭，今日既盟之后，来往莫相猜。\n白鹤在何处？尝试与偕来。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (645, '《贺新郎·别茂嘉十二弟》\n绿树听鹈鴂，更那堪、鹧鸪声住，杜鹃声切。\n啼到春归无寻处，苦恨芳菲都歇。\n算未抵、人间离别。\n马上琵琶关塞黑，更长门、翠辇辞金阙。\n看燕燕，送归妾。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (646, '《木兰花慢·滁州送范倅》\n老来情味减，对别酒，怯流年。\n况屈指中秋，十分好月，不照人圆。\n无情水都不管，共西风、只管送归船。\n秋晚莼鲈江上，夜深儿女灯前。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (647, '《祝英台近·晚春》\n宝钗分，桃叶渡，烟柳暗南浦。\n怕上层楼，十日九风雨。\n断肠片片飞红，都无人管，更谁劝、啼莺声住？\n鬓边觑，试把花卜归期，才簪又重数。\n罗帐灯昏，哽咽梦中语：是他春带愁来，春归何处？却不解、带将愁去。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (648, '《鹧鸪天·代人赋》\n晚日寒鸦一片愁，柳塘新绿却温柔。\n若教眼底无离恨，不信人间有白头。\n肠已断，泪难收，相思重上小红楼。\n情知已被山遮断，频倚阑干不自由。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (649, '《太常引·建康中秋夜为吕叔潜赋》\n一轮秋影转金波，飞镜又重磨。\n把酒问姮娥：被白发、欺人奈何？\n乘风好去，长空万里，直下看山河。\n斫去桂婆娑，人道是、清光更多。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (650, '《西江月·夜行黄沙道中》\n明月别枝惊鹊，清风半夜鸣蝉。\n稻花香里说丰年，听取蛙声一片。\n七八个星天外，两三点雨山前。\n旧时茅店社林边，路转溪桥忽见。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (651, '《沁园春·带湖新居将成》\n三径初成，鹤怨猿惊，稼轩未来。\n甚云山自许，平生意气；衣冠人笑，抵死尘埃。\n意倦须还，身闲贵早，岂为莼羹鲈脍哉？\n秋江上，看惊弦雁避，骇浪船回。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (652, '《沁园春·灵山齐庵赋时筑偃湖未成》\n叠嶂西驰，万马回旋，众山欲东。\n正惊湍直下，跳珠倒溅；小桥横截，缺月初弓。\n老合投闲，天教多事，检校长身十万松。\n吾庐小，在龙蛇影外，风雨声中。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (653, '《贺新郎·同父见和再用韵答之》\n老大那堪说。\n似而今、元龙臭味，孟公瓜葛。\n我病君来高歌饮，惊散楼头飞雪。\n笑富贵千钧如发。\n硬语盘空谁来听？记当时、只有西窗月。\n重进酒，换鸣瑟。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (654, '《贺新郎·用前韵送杜叔高》\n细把君诗说。\n怅余音、钧天浩荡，洞庭胶葛。\n千尺阴崖尘不到，惟有层冰积雪。\n乍一见、寒生毛发。\n自昔佳人多薄命，对古来、一片伤心月。\n金屋冷，夜调瑟。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (655, '《水龙吟·过南剑双溪楼》\n举头西北浮云，倚天万里须长剑。\n人言此地，夜深长见，斗牛光焰。\n我觉山高，潭空水冷，月明星淡。\n待燃犀下看，凭栏却怕，风雷怒，鱼龙惨。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (656, '《永遇乐·戏赋辛字送茂嘉十二弟赴调》\n烈日秋霜，忠肝义胆，千载家谱。\n得姓何年，细参辛字，一笑君听取。\n艰辛做就，悲辛滋味，总是辛酸辛苦。\n更十分、向人辛辣，椒桂捣残堪吐。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (657, '《汉宫春·会稽蓬莱阁怀古》\n秦望山头，看乱云急雨，倒立江湖。\n不知云者为雨，雨者云乎？\n长空万里，被西风、变灭须臾。\n回首听、月明天籁，人间万窍号呼。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (658, '《汉宫春·会稽秋风亭观雨》\n亭上秋风，记去年袅袅，曾到吾庐。\n山河举目虽异，风景非殊。\n功成者去，觉团扇、便与人疏。\n吹不断、斜阳依旧，茫茫禹迹都无。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (659, '《念奴娇·书东流村壁》\n野棠花落，又匆匆过了，清明时节。\n刬地东风欺客梦，一枕云屏寒怯。\n曲岸持觞，垂杨系马，此地曾经别。\n楼空人去，旧游飞燕能说。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (660, '《鹧鸪天·鹅湖归病起作》\n枕簟溪堂冷欲秋，断云依水晚来收。\n红莲相倚浑如醉，白鸟无言定自愁。\n书咄咄，且休休，一丘一壑也风流。\n不知筋力衰多少，但觉新来懒上楼。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (661, '《玉楼春·戏赋云山》\n何人半夜推山去？四面浮云猜是汝。\n常时相对两三峰，走遍溪头无觅处。\n西风瞥起云横度，忽见东南天一柱。\n老僧拍手笑相夸，且喜青山依旧住。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (662, '《踏莎行·庚戌中秋后二夕带湖篆冈小酌》\n夜月楼台，秋香院宇。笑吟吟地人来去。\n是谁秋到便凄凉？当年宋玉悲如许。\n随分杯盘，等闲歌舞。问他有甚堪悲处？\n思量却也有悲时，重阳节近多风雨。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (663, '《蝶恋花·戊申元日立春席间作》\n谁向椒盘簪彩胜？整整韶华，争上春风鬓。\n往日不堪重记省，为花长把新春恨。\n春未来时先借问。晚恨开迟，早又飘零近。\n今岁花期消息定，只愁风雨无凭准。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (664, '《临江仙·探梅》\n老去惜花心已懒，爱梅犹绕江村。\n一枝先破玉溪春。更无花态度，全有雪精神。\n剩向空山餐秀色，为渠著句清新。\n竹根流水带溪云。醉中浑不记，归路月黄昏。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (665, '《鹧鸪天·送人》\n唱彻《阳关》泪未干，功名馀事且加餐。\n浮天水送无穷树，带雨云埋一半山。\n今古恨，几千般，只应离合是悲欢？\n江头未是风波恶，别有人间行路难！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (666, '《鹧鸪天·代人赋》\n晚日寒鸦一片愁，柳塘新绿却温柔。\n若教眼底无离恨，不信人间有白头。\n肠已断，泪难收，相思重上小红楼。\n情知已被山遮断，频倚阑干不自由。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (667, '《鹧鸪天·鹅湖归病起作》\n枕簟溪堂冷欲秋，断云依水晚来收。\n红莲相倚浑如醉，白鸟无言定自愁。\n书咄咄，且休休，一丘一壑也风流。\n不知筋力衰多少，但觉新来懒上楼。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (668, '《鹧鸪天·送廓之秋试》\n白苎新袍入嫩凉。春蚕食叶响回廊。\n禹门已准桃花浪，月殿先收桂子香。\n鹏北海，凤朝阳。又携书剑路茫茫。\n明年此日青云去，却笑人间举子忙。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (669, '《鹧鸪天·有客慨然谈功名因追念少年时事戏作》\n壮岁旌旗拥万夫，锦襜突骑渡江初。\n燕兵夜娖银胡觮，汉箭朝飞金仆姑。\n追往事，叹今吾，春风不染白髭须。\n却将万字平戎策，换得东家种树书。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (670, '《鹧鸪天·陌上柔桑破嫩芽》\n陌上柔桑破嫩芽，东邻蚕种已生些。\n平冈细草鸣黄犊，斜日寒林点暮鸦。\n山远近，路横斜，青旗沽酒有人家。\n城中桃李愁风雨，春在溪头荠菜花。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (671, '《鹧鸪天·游鹅湖醉书酒家壁》\n春入平原荠菜花，新耕雨后落群鸦。\n多情白发春无奈，晚日青帘酒易赊。\n闲意态，细生涯。牛栏西畔有桑麻。\n青裙缟袂谁家女，去趁蚕生看外家。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (672, '《鹧鸪天·元夕有所梦》\n肥水东流无尽期，当初不合种相思。\n梦中未比丹青见，暗里忽惊山鸟啼。\n春未绿，鬓先丝。人间别久不成悲。\n谁教岁岁红莲夜，两处沉吟各自知。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (673, '《鹧鸪天·正月十一日观灯》\n巷陌风光纵赏时。笼纱未出马先嘶。\n白头居士无呵殿，只有乘肩小女随。\n花满市，月侵衣。少年情事老来悲。\n沙河塘上春寒浅，看了游人缓缓归。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (674, '《鹧鸪天·送元济之归豫章》\n敧枕婆娑两鬓霜。起听檐溜碎喧江。\n那边云筋销啼粉，这里车轮转别肠。\n诗酒社，水云乡。可堪醉墨几淋浪。\n画图恰似归家梦，千里河山寸许长。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (675, '《鹧鸪天·博山寺作》\n不向长安路上行。却教山寺厌逢迎。\n味无味处求吾乐，材不材间过此生。\n宁作我，岂其卿。人间走遍却归耕。\n一松一竹真朋友，山鸟山花好弟兄。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (676, '《鹧鸪天·黄沙道中即事》\n句里春风正剪裁。溪山一片画图开。\n轻鸥自趁虚船去，荒犬还迎野妇回。\n松共竹，翠成堆。要擎残雪斗疏梅。\n乱鸦毕竟无才思，时把琼瑶蹴下来。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (677, '《鹧鸪天·石门道中》\n山上飞泉万斛珠。悬崖千丈落鼪鼯。\n已通樵径行还碍，似有人声听却无。\n闲略彴，远浮屠。溪南修竹有茅庐。\n莫嫌杖屦频来往，此地偏宜著老夫。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (678, '《鹧鸪天·送欧阳国瑞入吴中》\n莫避春阴上马迟。春来未有不阴时。\n人情展转闲中看，客路崎岖倦后知。\n梅似雪，柳如丝。试听别语慰相思。\n短篷炊饮鲈鱼熟，除却松江枉费诗。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (679, '《鹧鸪天·三山道中》\n抛却山中诗酒窠。却来官府听笙歌。\n闲愁做弄天来大，白发栽埋日许多。\n新剑戟，旧风波。天生予懒奈予何。\n此身已觉浑无事，却教儿童莫恁么。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (680, '《鹧鸪天·读渊明诗不能去手戏作小词以送之》\n晚岁躬耕不怨贫。只鸡斗酒聚比邻。\n都无晋宋之间事，自是羲皇以上人。\n千载后，百篇存。更无一字不清真。\n若教王谢诸郎在，未抵柴桑陌上尘。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (681, '《鹧鸪天·和子似山行韵》\n谁共春光管日华。朱朱粉粉野蒿花。\n闲愁投老无多子，酒病而今较减些。\n山远近，路横斜。正无聊处管弦哗。\n去年醉处犹能记，细数溪边第几家。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (682, '《鹧鸪天·和昌父》\n万事纷纷一笑中。渊明把菊对秋风。\n细看爽气今犹在，惟有南山一似翁。\n情味好，语言工。三贤高会古来同。\n谁知止酒停云老，独立斜阳数过鸿。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (683, '《鹧鸪天·徐衡仲惠琴不受》\n千丈阴崖百丈溪。孤桐枝上凤偏宜。\n玉音落落虽难合，横理庚庚定自奇。\n人散后，月明时。试弹幽愤泪空垂。\n不如却付骚人手，留和南风解愠诗。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (684, '《鹧鸪天·代人赋》\n晚日寒鸦一片愁，柳塘新绿却温柔。\n若教眼底无离恨，不信人间有白头。\n肠已断，泪难收，相思重上小红楼。\n情知已被山遮断，频倚阑干不自由。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (685, '《鹧鸪天·送人》\n唱彻《阳关》泪未干，功名馀事且加餐。\n浮天水送无穷树，带雨云埋一半山。\n今古恨，几千般，只应离合是悲欢？\n江头未是风波恶，别有人间行路难！', 1, 2, NULL, NULL);
