INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (822, '《鹧鸪天·陌上柔桑破嫩芽》\n陌上柔桑破嫩芽，东邻蚕种已生些。\n平冈细草鸣黄犊，斜日寒林点暮鸦。\n山远近，路横斜，青旗沽酒有人家。\n城中桃李愁风雨，春在溪头荠菜花。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (823, '《鹧鸪天·游鹅湖醉书酒家壁》\n春入平原荠菜花，新耕雨后落群鸦。\n多情白发春无奈，晚日青帘酒易赊。\n闲意态，细生涯。牛栏西畔有桑麻。\n青裙缟袂谁家女，去趁蚕生看外家。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (824, '《鹧鸪天·元夕有所梦》\n肥水东流无尽期，当初不合种相思。\n梦中未比丹青见，暗里忽惊山鸟啼。\n春未绿，鬓先丝。人间别久不成悲。\n谁教岁岁红莲夜，两处沉吟各自知。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (825, '《鹧鸪天·正月十一日观灯》\n巷陌风光纵赏时。笼纱未出马先嘶。\n白头居士无呵殿，只有乘肩小女随。\n花满市，月侵衣。少年情事老来悲。\n沙河塘上春寒浅，看了游人缓缓归。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (826, '《鹧鸪天·送元济之归豫章》\n敧枕婆娑两鬓霜。起听檐溜碎喧江。\n那边云筋销啼粉，这里车轮转别肠。\n诗酒社，水云乡。可堪醉墨几淋浪。\n画图恰似归家梦，千里河山寸许长。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (827, '《鹧鸪天·博山寺作》\n不向长安路上行。却教山寺厌逢迎。\n味无味处求吾乐，材不材间过此生。\n宁作我，岂其卿。人间走遍却归耕。\n一松一竹真朋友，山鸟山花好弟兄。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (828, '《鹧鸪天·黄沙道中即事》\n句里春风正剪裁。溪山一片画图开。\n轻鸥自趁虚船去，荒犬还迎野妇回。\n松共竹，翠成堆。要擎残雪斗疏梅。\n乱鸦毕竟无才思，时把琼瑶蹴下来。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (829, '《鹧鸪天·石门道中》\n山上飞泉万斛珠。悬崖千丈落鼪鼯。\n已通樵径行还碍，似有人声听却无。\n闲略彴，远浮屠。溪南修竹有茅庐。\n莫嫌杖屦频来往，此地偏宜著老夫。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (830, '《鹧鸪天·送欧阳国瑞入吴中》\n莫避春阴上马迟。春来未有不阴时。\n人情展转闲中看，客路崎岖倦后知。\n梅似雪，柳如丝。试听别语慰相思。\n短篷炊饮鲈鱼熟，除却松江枉费诗。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (831, '《鹧鸪天·三山道中》\n抛却山中诗酒窠。却来官府听笙歌。\n闲愁做弄天来大，白发栽埋日许多。\n新剑戟，旧风波。天生予懒奈予何。\n此身已觉浑无事，却教儿童莫恁么。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (832, '《鹧鸪天·读渊明诗不能去手戏作小词以送之》\n晚岁躬耕不怨贫。只鸡斗酒聚比邻。\n都无晋宋之间事，自是羲皇以上人。\n千载后，百篇存。更无一字不清真。\n若教王谢诸郎在，未抵柴桑陌上尘。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (833, '《鹧鸪天·和子似山行韵》\n谁共春光管日华。朱朱粉粉野蒿花。\n闲愁投老无多子，酒病而今较减些。\n山远近，路横斜。正无聊处管弦哗。\n去年醉处犹能记，细数溪边第几家。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (834, '《鹧鸪天·和昌父》\n万事纷纷一笑中。渊明把菊对秋风。\n细看爽气今犹在，惟有南山一似翁。\n情味好，语言工。三贤高会古来同。\n谁知止酒停云老，独立斜阳数过鸿。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (835, '《鹧鸪天·徐衡仲惠琴不受》\n千丈阴崖百丈溪。孤桐枝上凤偏宜。\n玉音落落虽难合，横理庚庚定自奇。\n人散后，月明时。试弹幽愤泪空垂。\n不如却付骚人手，留和南风解愠诗。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (836, '《鹧鸪天·代人赋》\n晚日寒鸦一片愁，柳塘新绿却温柔。\n若教眼底无离恨，不信人间有白头。\n肠已断，泪难收，相思重上小红楼。\n情知已被山遮断，频倚阑干不自由。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (837, '《鹧鸪天·送人》\n唱彻《阳关》泪未干，功名馀事且加餐。\n浮天水送无穷树，带雨云埋一半山。\n今古恨，几千般，只应离合是悲欢？\n江头未是风波恶，别有人间行路难！', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (838, '《鹧鸪天·鹅湖归病起作》\n枕簟溪堂冷欲秋，断云依水晚来收。\n红莲相倚浑如醉，白鸟无言定自愁。\n书咄咄，且休休，一丘一壑也风流。\n不知筋力衰多少，但觉新来懒上楼。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (839, '《鹧鸪天·送廓之秋试》\n白苎新袍入嫩凉。春蚕食叶响回廊。\n禹门已准桃花浪，月殿先收桂子香。\n鹏北海，凤朝阳。又携书剑路茫茫。\n明年此日青云去，却笑人间举子忙。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (840, '《鹧鸪天·有客慨然谈功名因追念少年时事戏作》\n壮岁旌旗拥万夫，锦襜突骑渡江初。\n燕兵夜娖银胡觮，汉箭朝飞金仆姑。\n追往事，叹今吾，春风不染白髭须。\n却将万字平戎策，换得东家种树书。', 1, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (841, '《鹧鸪天·陌上柔桑破嫩芽》\n陌上柔桑破嫩芽，东邻蚕种已生些。\n平冈细草鸣黄犊，斜日寒林点暮鸦。\n山远近，路横斜，青旗沽酒有人家。\n城中桃李愁风雨，春在溪头荠菜花。', 1, 2, NULL, NULL);
