INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1668, 'A single rose, a silent tear,\nThe weight of love, the taste of fear.\nBut through the pain, the heart still sings,\nOf hope and joy that morning brings.', 2, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1669, 'In forests deep where no one roams,\nThe owls call from ancient homes.\nLeaves may fall and rivers bend,\nBut nature writes what none can end.', 2, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1670, 'The sun has set, the skies are red,\nA whispering breeze, the day is dead.\nThe stars arise, the moon takes flight,\nTo guard our dreams throughout the night.', 2, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1671, 'The sun has set, the skies are red,\nA whispering breeze, the day is dead.\nThe stars arise, the moon takes flight,\nTo guard our dreams throughout the night.', 2, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1672, 'Beneath the stars so vast and wide,\nThe ocean tells of time and tide.\nWaves may crash and storms may roar,\nBut peace will find the quiet shore.', 2, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1673, 'In forests deep where no one roams,\nThe owls call from ancient homes.\nLeaves may fall and rivers bend,\nBut nature writes what none can end.', 2, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1674, 'The sun has set, the skies are red,\nA whispering breeze, the day is dead.\nThe stars arise, the moon takes flight,\nTo guard our dreams throughout the night.', 2, 2, NULL, NULL);
INSERT INTO `language_content` (`id`, `content`, `language`, `type`, `translation`, `pronunciation`) VALUES (1675, 'Morning light on dewdrop’s gleam,\nWakes the world from silent dream.\nBirds arise to greet the sky,\nWith songs of hope that never die.', 2, 2, NULL, NULL);
